// Prepara os dados do arquivo para upload
const formData = $input.first().json;
const binaryData = $input.first().binary;

// Pega o arquivo do form
const fileKey = Object.keys(binaryData)[0];
const file = binaryData[fileKey];

if (!file) {
  throw new Error('Nenhum arquivo foi enviado');
}

return {
  fileName: file.fileName,
  fileSize: file.fileSize,
  mimeType: file.mimeType,
  pergunta: formData.pergunta,
  storeName: $('1. Criar File Search Store').first().json.name
};

// Extrai a URL de upload dos headers
const headers = $input.first().json.headers;
let uploadUrl = '';

for (const [key, value] of Object.entries(headers)) {
  if (key.toLowerCase() === 'x-goog-upload-url') {
    uploadUrl = value;
    break;
  }
}

if (!uploadUrl) {
  throw new Error('Upload URL não encontrada nos headers');
}

const prepData = $('Preparar Dados do Arquivo').first().json;

return {
  uploadUrl,
  fileName: prepData.fileName,
  fileSize: prepData.fileSize,
  mimeType: prepData.mimeType,
  pergunta: prepData.pergunta,
  storeName: prepData.storeName
};

// Prepara dados para polling da indexação
const response = $input.first().json;
const extractData = $('3. Extrair Upload URL').first().json;

if (!response.name) {
  throw new Error('Nome da operação não encontrado');
}

return {
  operationName: response.name,
  storeName: extractData.storeName,
  pergunta: extractData.pergunta,
  done: response.done || false,
  tentativas: 0
};

// Atualiza status e incrementa tentativas
const response = $input.first().json;
const prevData = $('Aguardar 5s').first().json;

const tentativas = (prevData.tentativas || 0) + 1;

if (tentativas > 20) {
  throw new Error('Timeout: Indexação demorou mais de 100 segundos');
}

return {
  operationName: prevData.operationName,
  storeName: prevData.storeName,
  pergunta: prevData.pergunta,
  done: response.done || false,
  tentativas: tentativas
};

// Extrai resposta e citações
const response = $input.first().json;

if (!response.candidates || response.candidates.length === 0) {
  return {
    erro: 'Nenhuma resposta gerada',
    respostaCompleta: response
  };
}

const candidate = response.candidates[0];
const texto = candidate.content?.parts?.[0]?.text || 'Sem texto';
const citacoes = candidate.groundingMetadata || null;

// Formata as citações de forma legível
let citacoesFormatadas = [];
if (citacoes?.groundingChunks) {
  citacoesFormatadas = citacoes.groundingChunks.map((chunk, idx) => ({
    indice: idx + 1,
    texto: chunk.web?.title || 'Sem título',
    trecho: chunk.web?.uri || 'Sem URI'
  }));
}

return {
  pergunta: $('5. Preparar Polling').first().json.pergunta,
  resposta: texto,
  citacoes: citacoesFormatadas,
  metadadosCitacoes: citacoes,
  respostaCompleta: response
};

